/**
 * Generated by `createservice user.SignInUserService --type mutations`
 */

const get = require('lodash/get')

const conf = require('@open-condo/config')
const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema, find, getSchemaCtx, getById } = require('@open-condo/keystone/schema')

const { DV_VERSION_MISMATCH, WRONG_FORMAT, NOT_FOUND } = require('@condo/domains/common/constants/errors')
const { normalizeEmail } = require('@condo/domains/common/utils/mail')
const { normalizePhone } = require('@condo/domains/common/utils/phone')
const access = require('@condo/domains/user/access/SignInUserService')
const { SERVICE, STAFF, RESIDENT, MAX_ANONYMOUS_REQUESTS_FOR_IP_BY_DAY } = require('@condo/domains/user/constants/common')
const { GQL_ERRORS } = require('@condo/domains/user/constants/errors')
const { ConfirmPhoneAction, User } = require('@condo/domains/user/utils/serverSchema')
const { RedisGuard } = require('@condo/domains/user/utils/serverSchema/guards')


/**
 * List of possible errors, that this custom schema can throw
 * They will be rendered in documentation section in GraphiQL for this custom schema
 */
const ERRORS = {
    REQUIRED_USER_DATA_IS_MISSING: (missingFields = []) => ({
        mutation: 'signInUser',
        variable: ['data', 'userData', missingFields[0]],
        code: BAD_USER_INPUT,
        type: 'REQUIRED_USER_DATA_IS_MISSING',
        message: `Some required user data was missing: ${missingFields.join(', ')}`,
        messageForUser: 'api.user.signInUser.REQUIRED_USER_DATA_IS_MISSING',
    }),
    NOT_AVAILABLE_FOR_USER_WITH_SERVICE_TYPE: {
        mutation: 'signInUser',
        variable: ['data', 'userType'],
        code: BAD_USER_INPUT,
        type: 'NOT_AVAILABLE_FOR_USER_WITH_SERVICE_TYPE',
        message: 'Not available for service users',
    },
    DIFFERENT_PHONE_NUMBERS: {
        mutation: 'signInUser',
        variable: ['data', 'userData', 'phone'],
        code: BAD_USER_INPUT,
        type: 'DIFFERENT_PHONE_NUMBERS',
        message: 'The verified phone number and the phone number from the payload cannot be different',
    },
    INVALID_PHONE_NUMBER: {
        mutation: 'signInUser',
        code: BAD_USER_INPUT,
        type: 'INVALID_PHONE_NUMBER',
        message: 'Invalid phone number',
        messageForUser: 'api.user.signInUser.INVALID_PHONE_NUMBER',
    },
    USER_NOT_FOUND: {
        mutation: 'signInUser',
        code: NOT_FOUND,
        type: 'USER_NOT_FOUND',
        message: 'User not found',
        messageForUser: 'api.user.signInUser.USER_NOT_FOUND',
    },
    TOKEN_NOT_FOUND: {
        mutation: 'signInUser',
        variable: ['data', 'token'],
        code: NOT_FOUND,
        type: 'TOKEN_NOT_FOUND',
        message: 'Token not found',
    },
    MULTIPLE_USERS_FOUND: {
        mutation: 'signInUser',
        code: NOT_FOUND,
        type: 'MULTIPLE_USERS_FOUND',
        message: 'Multiple users found',
    },
    DV_VERSION_MISMATCH: {
        query: 'signInUser',
        variable: ['data', 'dv'],
        code: BAD_USER_INPUT,
        type: DV_VERSION_MISMATCH,
        message: 'Wrong value for data version number',
    },
    WRONG_SENDER_FORMAT: {
        query: 'signInUser',
        variable: ['data', 'sender'],
        code: BAD_USER_INPUT,
        type: WRONG_FORMAT,
        message: 'Invalid format of "sender" field value',
        correctExample: '{ dv: 1, fingerprint: \'example-fingerprint-alphanumeric-value\'}',
    },
}


const REDIS_GUARD = new RedisGuard()
const MAX_ANONYMOUS_REQUESTS_BY_DAY = Number(conf['MAX_ANONYMOUS_REQUESTS_FOR_IP_BY_DAY']) || MAX_ANONYMOUS_REQUESTS_FOR_IP_BY_DAY
const IP_WHITE_LIST = conf.IP_WHITE_LIST ? JSON.parse(conf.IP_WHITE_LIST) : []

const REQUIRED_USER_FIELDS_BY_TYPE = {
    [RESIDENT]: ['phone'],
    [STAFF]: ['phone', 'name', 'password'],
}

const getUserPayload = (user, userData) => {
    const payload = {}
    for (const [key, value] of Object.entries(userData))  {
        if (!value) continue
        if (get(user, key)) continue
        payload[key] = value
    }
    return payload
}

const checkRequiredUserFields = (requiredFields, userData) => {
    if (!Array.isArray(requiredFields)) throw new Error('"requiredFields" should be an array')

    const missingFields = []
    for (const field of requiredFields) {
        const value = get(userData, field, null)
        if (!value && typeof value !== 'boolean' && typeof value !== 'number') missingFields.push(field)
    }
    return { missingRequiredFields: missingFields.length > 0, missingFields }
}

const checkDayRequestLimitCounters = async (context, rawIp) => {
    const ip = rawIp.split(':').pop()
    const key = `signInUser:ip:${ip}`
    const byIpCounter = await REDIS_GUARD.incrementDayCounter(key)
    if (byIpCounter > MAX_ANONYMOUS_REQUESTS_BY_DAY && !IP_WHITE_LIST.includes(ip)) {
        throw new GQLError(GQL_ERRORS.SMS_FOR_IP_DAY_LIMIT_REACHED, context)
    }
}

const SignInUserService = new GQLCustomSchema('SignInUserService', {
    types: [
        {
            access: true,
            type: 'input SignInUserUserDataInput { phone: String, name: String, email: String, password: String, meta: JSON }',
        },
        {
            access: true,
            type: 'input SignInUserInput { dv: Int!, sender: SenderFieldInput!, confirmActionToken: ID!, userType: UserTypeType!, userData: SignInUserUserDataInput }',
        },
        {
            access: true,
            type: 'type SignInUserOutput { user: User, token: ID! }',
        },
    ],

    mutations: [
        {
            access: access.canSignInUser,
            schema: 'signInUser(data: SignInUserInput!): SignInUserOutput',
            doc: {
                summary: 'This mutation authorizes the user by token, after confirming the phone number.\n\n' +
                    'If the user is not registered, then he will be created with the data that is passed in the payload (user data).\n\n' +
                    'If the existing user is missing some fields, then these fields will be taken from the payload (user data) and updated.\n\n' +
                    'This mutation is not available for service users!',
                errors: Object.fromEntries(Object.entries(ERRORS).filter(([key, error]) => typeof error === 'object')),
            },
            resolver: async (parent, args, context, info, extra = {}) => {
                const { data } = args
                const { confirmActionToken, userType, userData, dv, sender } = data

                await checkDayRequestLimitCounters(context, context.req.ip)

                const dvAndSender = { dv, sender }
                const userInfo = {
                    ...userData,
                    type: userType,
                    name: String(get(userData, 'name', '')).trim() || null,
                    email: normalizeEmail(get(userData, 'email')) || null,
                    isEmailVerified: false,
                    phone: normalizePhone(get(userData, 'phone')) || null,
                    isPhoneVerified: false,
                }

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                if (userType === SERVICE) throw new GQLError(ERRORS.NOT_AVAILABLE_FOR_USER_WITH_SERVICE_TYPE, context)

                if (!confirmActionToken) throw new GQLError(ERRORS.TOKEN_NOT_FOUND, context)

                const action = await ConfirmPhoneAction.getOne(context,
                    {
                        token: confirmActionToken,
                        expiresAt_gte: new Date().toISOString(),
                        completedAt: null,
                        isPhoneVerified: true,
                    }
                )
                if (!action) throw new GQLError(ERRORS.TOKEN_NOT_FOUND, context)

                const phoneFromAction = normalizePhone(action.phone) || null
                if (!!userInfo.phone && userInfo.phone !== phoneFromAction) throw new GQLError(ERRORS.DIFFERENT_PHONE_NUMBERS, context)
                if (!phoneFromAction) throw new GQLError(ERRORS.INVALID_PHONE_NUMBER, context)

                userInfo.phone = phoneFromAction
                userInfo.isPhoneVerified = action.isPhoneVerified

                const users = await find('User', { type: userInfo.type, phone: userInfo.phone })
                if (users.length > 1) throw new GQLError(ERRORS.MULTIPLE_USERS_FOUND, context)

                let user = users[0]
                if (user && user.deletedAt) throw new GQLError(ERRORS.USER_NOT_FOUND, context)

                const userPayload = getUserPayload(user, userInfo)

                if (!user) {
                    const { missingRequiredFields, missingFields } = checkRequiredUserFields(REQUIRED_USER_FIELDS_BY_TYPE[userType], userPayload)
                    if (missingRequiredFields) {
                        throw new GQLError(ERRORS.REQUIRED_USER_DATA_IS_MISSING(missingFields), context)
                    }

                    user = await User.create(context, { ...userPayload, ...dvAndSender })
                } else if (Object.keys(userPayload).length > 0) {
                    user = await User.update(context, user.id, { ...userPayload, ...dvAndSender })
                }

                await ConfirmPhoneAction.update(context, action.id, { dv: 1, sender, completedAt: new Date().toISOString() })
                const { keystone } = getSchemaCtx('User')
                const sessionToken = await context.startAuthedSession({ item: user, list: keystone.lists['User'] })

                return {
                    user: await getById('User', user.id),
                    token: sessionToken,
                }
            },
        },
    ],
    
})

module.exports = {
    SignInUserService,
    ERRORS,
}
